import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Search, Filter, Play, Lock, Globe, Dumbbell } from 'lucide-react';
import API from '../utils/api';
import { useAuth } from '../context/AuthContext';

const MUSCLE_GROUPS = [
  { key: 'all', label: 'All' },
  { key: 'chest', label: 'Chest' },
  { key: 'back', label: 'Back' },
  { key: 'shoulders', label: 'Shoulders' },
  { key: 'arms', label: 'Arms' },
  { key: 'biceps', label: 'Biceps' },
  { key: 'triceps', label: 'Triceps' },
  { key: 'legs', label: 'Legs' },
  { key: 'glutes', label: 'Glutes' },
  { key: 'core', label: 'Core' },
  { key: 'abs', label: 'Abs' },
  { key: 'cardio', label: 'Cardio' },
  { key: 'full-body', label: 'Full Body' },
];

const DIFFICULTY_COLORS = {
  beginner: 'text-green-400 bg-green-400/10',
  intermediate: 'text-yellow-400 bg-yellow-400/10',
  advanced: 'text-red-400 bg-red-400/10',
};

export default function ExercisesPage() {
  const [exercises, setExercises] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [searchParams, setSearchParams] = useSearchParams();
  const [activeMuscle, setActiveMuscle] = useState(searchParams.get('muscle') || 'all');
  const { user } = useAuth();

  useEffect(() => {
    setLoading(true);
    const params = activeMuscle !== 'all' ? `?muscleGroup=${activeMuscle}` : '';
    API.get(`/exercises${params}`)
      .then(res => setExercises(res.data))
      .catch(() => setExercises([]))
      .finally(() => setLoading(false));
  }, [activeMuscle]);

  const filtered = exercises.filter(e =>
    e.title.toLowerCase().includes(search.toLowerCase()) ||
    e.muscleGroup?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-[#0a0a0f] pt-20">
      {/* Header */}
      <div className="relative bg-gradient-to-br from-orange-900/20 to-transparent border-b border-white/10 py-16">
        <div className="max-w-7xl mx-auto px-6 text-center">
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
            <Dumbbell size={40} className="text-orange-400 mx-auto mb-4" />
            <h1 className="gym-font text-6xl text-white mb-3">EXERCISE <span className="gradient-text">LIBRARY</span></h1>
            <p className="text-gray-400 text-lg">Browse exercises by muscle group — with video guides & instructions</p>
          </motion.div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-10">
        {/* Search */}
        <div className="relative mb-8 max-w-md">
          <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
          <input
            className="input-dark pl-10"
            placeholder="Search exercises..."
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>

        {/* Muscle group tabs */}
        <div className="flex gap-2 flex-wrap mb-10">
          {MUSCLE_GROUPS.map(mg => (
            <button
              key={mg.key}
              onClick={() => setActiveMuscle(mg.key)}
              className={`px-4 py-2 rounded-full text-sm font-medium transition-all ${
                activeMuscle === mg.key
                  ? 'bg-orange-500 text-white'
                  : 'bg-white/5 text-gray-400 hover:bg-white/10 border border-white/10'
              }`}
            >
              {mg.label}
            </button>
          ))}
        </div>

        {/* Exercise Grid */}
        {loading ? (
          <div className="flex justify-center py-20">
            <div className="w-10 h-10 border-2 border-orange-500 border-t-transparent rounded-full animate-spin" />
          </div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-20 text-gray-500">No exercises found</div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filtered.map((ex, i) => (
              <motion.div
                key={ex._id}
                initial={{ opacity: 0, y: 30 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.05, duration: 0.4 }}
              >
                <Link to={`/exercises/${ex._id}`} className="block glass rounded-xl overflow-hidden group hover:border-orange-500/30 transition-all">
                  <div className="relative h-48 bg-gray-900 overflow-hidden">
                    {ex.image ? (
                      <img src={ex.image} alt={ex.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center">
                        <Dumbbell size={48} className="text-gray-700" />
                      </div>
                    )}
                    {ex.video && (
                      <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/40">
                        <div className="w-12 h-12 bg-orange-500/90 rounded-full flex items-center justify-center">
                          <Play size={22} className="text-white ml-1" />
                        </div>
                      </div>
                    )}
                    {!ex.isPublic && (
                      <div className="absolute top-2 right-2 flex items-center gap-1 bg-black/70 rounded-full px-2 py-1 text-xs text-yellow-400">
                        <Lock size={10} /> Private
                      </div>
                    )}
                    <div className="absolute top-2 left-2 bg-black/70 rounded-full px-2 py-1 text-xs text-gray-300 capitalize">
                      {ex.muscleGroup}
                    </div>
                  </div>
                  <div className="p-4">
                    <h3 className="text-white font-semibold mb-1 line-clamp-1">{ex.title}</h3>
                    <p className="text-gray-500 text-xs line-clamp-2 mb-3">{ex.description}</p>
                    <div className="flex items-center justify-between">
                      <span className={`text-xs px-2 py-0.5 rounded-full font-medium capitalize ${DIFFICULTY_COLORS[ex.difficulty] || ''}`}>
                        {ex.difficulty}
                      </span>
                      {ex.sets && <span className="text-xs text-gray-500">{ex.sets} sets × {ex.reps}</span>}
                    </div>
                  </div>
                </Link>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
